import{_ as e,o as t,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F03: 合約負債與營收能見度 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3680_家登/20260509/F03_合約負債與營收能見度.md","filePath":"審計報告庫/財務審計/3680_家登/20260509/F03_合約負債與營收能見度.md"}'),o={name:"審計報告庫/財務審計/3680_家登/20260509/F03_合約負債與營收能見度.md"};function l(n,a,s,h,d,c){return t(),i("div",null,[...a[0]||(a[0]=[r('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f03-合約負債與營收能見度-財務審計專家報告" tabindex="-1">F03: 合約負債與營收能見度 - 財務審計專家報告 <a class="header-anchor" href="#f03-合約負債與營收能見度-財務審計專家報告" aria-label="Permalink to &quot;F03: 合約負債與營收能見度 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>合約負債與未來收入的變動關係？訂單轉化為實質營收的速度是否出現停滯？透過合約負債測算營收能見度。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：合約負債從 9.48 億降至 3.05 億（-67.8%），能見度從 65% 降至 13.4%。主因大客戶付款條件變更而非訂單消失，管理層指引 2026 雙位數成長。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：2025 Q4</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>合約負債 7.09 億（2022Q4）→ 3.05 億（2025Q4），3 年縮減 57%。能見度從 63.3% 驟降至 13.4%，但同期營收從 13.22 億增至 22.68 億創單季新高。合約負債高峰 2023Q1 達 9.48 億後逐季下滑，主因客戶 A（台積電 45.25%）調整付款條件。ASML High-NA 已認證，CoWoS 載具認證進行中，低水位可能為新常態。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、訂單領先指標" tabindex="-1">一、訂單領先指標 <a class="header-anchor" href="#一、訂單領先指標" aria-label="Permalink to &quot;一、訂單領先指標&quot;">​</a></h3><p>合約負債高峰 2023 Q1 達 9.48 億後逐季下滑，同期營收從 51.98 億增至 70.56 億（+35.7%），兩者反向走勢反映合約負債「轉化加速」而非需求消失。2025 Q4 合約負債 3.05 億但營收創單季 22.68 億新高，代表合約模式已從先收款後出貨轉向出貨後收款。</p><h3 id="二、含金量分析" tabindex="-1">二、含金量分析 <a class="header-anchor" href="#二、含金量分析" aria-label="Permalink to &quot;二、含金量分析&quot;">​</a></h3><p>客戶 A（台積電）貢獻營收 33.25 億佔 45.25%（年增 10.6pp），集中度攀升解釋了合約負債下滑——大客戶調整付款條件。但 ASML High-NA 獨家認證確保 High-NA 世代訂單品質，航太訂單能見度達數年也有助分散風險。</p><h3 id="三、壓力測試" tabindex="-1">三、壓力測試 <a class="header-anchor" href="#三、壓力測試" aria-label="Permalink to &quot;三、壓力測試&quot;">​</a></h3><p>以 Q4 日均營收 2,468 萬計算，合約負債 3.05 億僅支撐約 12 天訂單轉化，半導體業偏低。但 EUV 光罩盒屬耗材型訂單，出貨週期短。Q1 2026 營收 YoY +30.2% 驗證需求存在，低水位可能成為新常態。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析（Skepticism Mandate） <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析（Skepticism Mandate）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>合約負債 11 季未見回升的結構性警訊</strong>：即使扣除付款條件變更，仍無法排除客戶避險行為意涵，是最早期的動能枯竭<strong>警訊</strong>。</li><li><strong>台積電 45% 集中度壓力</strong>：若再縮短付款週期，營運資金管理將承受更大<strong>壓力</strong>，與 FCF 為負相互印證。</li><li><strong>12 天能見度過短</strong>：不再享有客戶資金提前挹注，須以自有資金墊付庫存生產。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>營收 Q1 +30.2%、4 月 8.86 億創新高</strong>驗證需求持續擴張。</li><li><strong>ASML High-NA + CoWoS 認證</strong>提供長期高壁壘訂單保障。</li><li><strong>航太訂單數年能見度</strong>緩衝半導體週期波動。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>合約負債下降反映客戶付款條件變更，非訂單衰退。但 12 天能見度仍需觀察：若 2026 H2 仍未回升，管理層 2027 年指引可信度將被削弱。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：數據採集器.py (balance_sheet 3680 2022-01-01 2026-05-09) + (finance 3680 2022-01-01 2026-05-09)</li><li>原始數據：FinMind TaiwanStockBalanceSheet (CurrentContractLiabilities), TaiwanStockFinancialStatements (Revenue)</li><li>搜尋驗證：Fugle 法說會摘要 (2025-07-04)、CNA news (2026-01-09)</li><li>查詢參數：stock_id=3680, start=2022-01-01, end=2026-05-09</li><li>數據查詢日期：2026-05-09</li></ul>',24)])])}const p=e(o,[["render",l]]);export{u as __pageData,p as default};
